import json

import yaml

from prompty.model import SessionRef


def test_load_json_sessionref():
    json_data = r"""
    {
      "sessionId": "sess_abc123",
      "refType": "issue",
      "refValue": "owner/repo#123",
      "turnIndex": 2,
      "createdAt": "2026-06-09T20:00:00Z"
    }
    """
    data = json.loads(json_data, strict=False)
    instance = SessionRef.load(data)
    assert instance is not None
    assert instance.session_id == "sess_abc123"
    assert instance.ref_type == "issue"
    assert instance.ref_value == "owner/repo#123"
    assert instance.turn_index == 2
    assert instance.created_at == "2026-06-09T20:00:00Z"


